102	// This enum only defines values that are valid for Matrix component types.
103	// Each enumeration's value matches the cooresponding DXIL constant.
104	struct ComponentType {
105	  enum ComponentEnum {
106	    // Signed integers.
107	    __COMPONENT_TYPE(I8),
108	    __COMPONENT_TYPE(I16),
109	    __COMPONENT_TYPE(I32),
110	    __COMPONENT_TYPE(I64),
111	
