113	    __COMPONENT_TYPE(U8),
114	    __COMPONENT_TYPE(U16),
115	    __COMPONENT_TYPE(U32),
116	    __COMPONENT_TYPE(U64),
117	
118	    // Floating point types.
119	    __COMPONENT_TYPE(F8_E4M3FN),
120	    __COMPONENT_TYPE(F8_E5M2),
121	    __COMPONENT_TYPE(F16),
122	    __COMPONENT_TYPE(F32),
123	    __COMPONENT_TYPE(F64),
124	  };
