168	#define __MATRIX_SCALAR_COMPONENT_MAPPING(enum_val, type)                      \
169	  template <> struct ComponentTypeTraits<enum_val> {                           \
170	    using Type = type;                                                         \
171	    static const bool IsNativeScalar = true;                                   \
172	    static const uint ElementsPerScalar = 1;                                   \
173	  };
