176	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::I16, int16_t)
177	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::U16, uint16_t)
178	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::F16, float16_t)
179	#endif
