182	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::U32, uint32_t)
183	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::F32, float)
184	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::I64, int64_t)
185	__MATRIX_SCALAR_COMPONENT_MAPPING(ComponentType::U64, uint64_t)
