188	template <ComponentEnum DstTy, ComponentEnum SrcTy, int SrcN> struct DstN {
189	  static const int Value =
190	      (SrcN * ComponentTypeTraits<SrcTy>::ElementsPerScalar) /
191	      ComponentTypeTraits<DstTy>::ElementsPerScalar;
192	};
