201	template <typename T, int N, ComponentEnum DT> struct InterpretedVector {
202	  vector<T, N> Data;
203	  static const ComponentEnum Interpretation = DT;
204	  static const SIZE_TYPE Size =
205	      __detail::ComponentTypeTraits<DT>::ElementsPerScalar * N;
206	};
207	
208	template <ComponentEnum DT, typename T, int N>
209	InterpretedVector<T, N, DT> MakeInterpretedVector(vector<T, N> Vec) {
210	  InterpretedVector<T, N, DT> IV = {Vec};
211	  return IV;
212	}
213	
214	template <ComponentEnum DestTy, ComponentEnum OriginTy, typename T, int N>
215	InterpretedVector<typename __detail::ComponentTypeTraits<DestTy>::Type,
216	                  __detail::DstN<DestTy, OriginTy, N>::Value, DestTy>
217	Convert(vector<T, N> Vec) {
218	  vector<typename __detail::ComponentTypeTraits<DestTy>::Type,
219	         __detail::DstN<DestTy, OriginTy, N>::Value>
220	      Result;
221	  __builtin_LinAlg_Convert(Result, Vec, OriginTy, DestTy);
222	  return MakeInterpretedVector<DestTy>(Result);
223	}
