225	template <ComponentEnum ComponentTy, SIZE_TYPE M, SIZE_TYPE N,
226	          MatrixUseEnum Use, MatrixScopeEnum Scope>
227	class Matrix {
228	  using ElementType = typename __detail::ComponentTypeTraits<ComponentTy>::Type;
229	  // If this isn't a native scalar, we have an 8-bit type, so we have 4 elements
230	  // packed in each scalar value.
231	  static const uint ElementsPerScalar =
232	      __detail::ComponentTypeTraits<ComponentTy>::ElementsPerScalar;
233	  static const bool IsNativeScalar =
234	      __detail::ComponentTypeTraits<ComponentTy>::IsNativeScalar;
235	
236	  using HandleT = __builtin_LinAlgMatrix
237	      [[__LinAlgMatrix_Attributes(ComponentTy, M, N, Use, Scope)]];
238	  HandleT __handle;
239	
240	  template <ComponentEnum NewCompTy, MatrixUseEnum NewUse = Use,
241	            bool Transpose = false>
242	  Matrix<NewCompTy, M, N, NewUse, Scope> Cast() {
243	    Matrix<NewCompTy, M, N, NewUse, Scope> Result;
244	    __builtin_LinAlg_CopyConvertMatrix(Result.__handle, __handle, Transpose);
245	    return Result;
246	  }
247	
248	  template <typename T>
249	  static typename hlsl::enable_if<hlsl::is_arithmetic<T>::value, Matrix>::type
250	  Splat(T Val) {
251	    Matrix Result;
252	    __builtin_LinAlg_FillMatrix(Result.__handle, Val);
253	    return Result;
254	  }
255	
256	  static Matrix Load(ByteAddressBuffer Res, uint StartOffset, uint Stride,
257	                     MatrixLayoutEnum Layout,
258	                     uint Align = sizeof(ElementType)) {
259	    Matrix Result;
260	    __builtin_LinAlg_MatrixLoadFromDescriptor(Result.__handle, Res, StartOffset,
261	                                              Stride, Layout, Align);
262	    return Result;
263	  }
264	
265	  static Matrix Load(RWByteAddressBuffer Res, uint StartOffset, uint Stride,
266	                     MatrixLayoutEnum Layout,
267	                     uint Align = sizeof(ElementType)) {
268	    Matrix Result;
269	    __builtin_LinAlg_MatrixLoadFromDescriptor(Result.__handle, Res, StartOffset,
270	                                              Stride, Layout, Align);
271	    return Result;
272	  }
273	
274	  template <typename T, SIZE_TYPE Size>
275	  static typename hlsl::enable_if<hlsl::is_arithmetic<T>::value &&
276	                                      (M * N / ElementsPerScalar <= Size),
277	                                  Matrix>::type
278	  Load(groupshared T Arr[Size], uint StartIdx, uint Stride,
279	       MatrixLayoutEnum Layout) {
280	    Matrix Result;
281	    __builtin_LinAlg_MatrixLoadFromMemory(Result.__handle, Arr, StartIdx,
282	                                          Stride, Layout);
283	    return Result;
284	  }
285	
286	  template <ComponentEnum LocalComp = ComponentTy>
287	  typename hlsl::enable_if<LocalComp == ComponentTy && IsNativeScalar,
288	                           uint>::type
289	  Length() {
290	    return __builtin_LinAlg_MatrixLength(__handle);
291	  }
292	
293	  template <ComponentEnum LocalComp = ComponentTy>
294	  typename hlsl::enable_if<LocalComp == ComponentTy && IsNativeScalar,
295	                           uint2>::type
296	  GetCoordinate(uint Index) {
297	    return __builtin_LinAlg_MatrixGetCoordinate(__handle, Index);
298	  }
299	
300	  template <ComponentEnum LocalComp = ComponentTy>
301	  typename hlsl::enable_if<LocalComp == ComponentTy && IsNativeScalar,
302	                           ElementType>::type
303	  Get(uint Index) {
304	    ElementType Result;
305	    __builtin_LinAlg_MatrixGetElement(Result, __handle, Index);
306	    return Result;
307	  }
308	
309	  template <ComponentEnum LocalComp = ComponentTy>
310	  typename hlsl::enable_if<LocalComp == ComponentTy && IsNativeScalar,
311	                           void>::type
312	  Set(uint Index, ElementType Value) {
313	    __builtin_LinAlg_MatrixSetElement(__handle, __handle, Index, Value);
314	  }
315	
316	  void Store(RWByteAddressBuffer Res, uint StartOffset, uint Stride,
317	             MatrixLayoutEnum Layout, uint Align = sizeof(ElementType)) {
318	    __builtin_LinAlg_MatrixStoreToDescriptor(__handle, Res, StartOffset, Stride,
319	                                             Layout, Align);
320	  }
321	
322	  template <typename T, SIZE_TYPE Size>
323	  typename hlsl::enable_if<hlsl::is_arithmetic<T>::value &&
324	                               (M * N / ElementsPerScalar <= Size),
325	                           void>::type
326	  Store(groupshared T Arr[Size], uint StartIdx, uint Stride,
327	        MatrixLayoutEnum Layout) {
328	    __builtin_LinAlg_MatrixStoreToMemory(__handle, Arr, StartIdx, Stride,
329	                                         Layout);
330	  }
331	
332	  // Accumulate methods
333	  template <MatrixUseEnum UseLocal = Use>
334	  typename hlsl::enable_if<Use == MatrixUse::Accumulator && UseLocal == Use,
335	                           void>::type
336	  InterlockedAccumulate(RWByteAddressBuffer Res, uint StartOffset, uint Stride,
337	                        MatrixLayoutEnum Layout,
338	                        uint Align = sizeof(ElementType)) {
339	    __builtin_LinAlg_MatrixAccumulateToDescriptor(__handle, Res, StartOffset,
340	                                                  Stride, Layout, Align);
341	  }
342	
343	  template <typename T, MatrixUseEnum UseLocal = Use,
344	            MatrixScopeEnum ScopeLocal = Scope, SIZE_TYPE Size>
345	  typename hlsl::enable_if<
346	      hlsl::is_arithmetic<T>::value && Use == MatrixUse::Accumulator &&
347	          UseLocal == Use && (M * N / ElementsPerScalar <= Size) &&
348	          Scope == MatrixScope::Wave && ScopeLocal == Scope,
349	      void>::type
350	  InterlockedAccumulate(groupshared T Arr[Size], uint StartIdx, uint Stride,
351	                        MatrixLayoutEnum Layout) {
352	    __builtin_LinAlg_MatrixAccumulateToMemory(__handle, Arr, StartIdx, Stride,
353	                                              Layout);
354	  }
355	
356	  template <ComponentEnum CompTy, MatrixUseEnum UseLocal = Use>
357	  typename hlsl::enable_if<Use == MatrixUse::Accumulator && UseLocal == Use,
358	                           void>::type
359	  Accumulate(const Matrix<CompTy, M, N, MatrixUse::A, Scope> MatrixA) {
360	    __builtin_LinAlg_MatrixAccumulate(__handle, __handle, MatrixA.__handle);
361	  }
362	
363	  template <ComponentEnum CompTy, MatrixUseEnum UseLocal = Use>
364	  typename hlsl::enable_if<Use == MatrixUse::Accumulator && UseLocal == Use,
365	                           void>::type
366	  Accumulate(const Matrix<CompTy, M, N, MatrixUse::B, Scope> MatrixB) {
367	    __builtin_LinAlg_MatrixAccumulate(__handle, __handle, MatrixB.__handle);
368	  }
369	
370	  template <ComponentEnum LHSTy, ComponentEnum RHSTy, SIZE_TYPE K,
371	            MatrixUseEnum UseLocal = Use>
372	  typename hlsl::enable_if<Use == MatrixUse::Accumulator && UseLocal == Use,
373	                           void>::type
374	  MultiplyAccumulate(const Matrix<LHSTy, M, K, MatrixUse::A, Scope> MatrixA,
375	                     const Matrix<RHSTy, K, N, MatrixUse::B, Scope> MatrixB) {
376	    __builtin_LinAlg_MatrixMatrixMultiplyAccumulate(__handle, MatrixA.__handle,
377	                                                    MatrixB.__handle, __handle);
378	  }
379	};
