381	// Thread-scope Matrices are read-only. Using a template partial
382	// specialization for this simplifies the SFINAE-foo above.
383	template <ComponentEnum ComponentTy, SIZE_TYPE M, SIZE_TYPE N,
384	          MatrixUseEnum Use>
385	class Matrix<ComponentTy, M, N, Use, MatrixScope::Thread> {
386	  using ElementType = typename __detail::ComponentTypeTraits<ComponentTy>::Type;
387	
388	  using HandleT = __builtin_LinAlgMatrix [[__LinAlgMatrix_Attributes(
389	      ComponentTy, M, N, Use, MatrixScope::Thread)]];
390	  HandleT __handle;
391	
392	  template <MatrixLayoutEnum Layout, MatrixUseEnum UseLocal = Use>
393	  static typename hlsl::enable_if<Use == MatrixUse::A && UseLocal == Use,
394	                                  Matrix>::type
395	  Load(ByteAddressBuffer Res, uint StartOffset, uint Stride,
396	       uint Align = sizeof(ElementType)) {
397	    Matrix Result;
398	    __builtin_LinAlg_MatrixLoadFromDescriptor(Result.__handle, Res, StartOffset,
399	                                              Stride, Layout, Align);
400	    return Result;
401	  }
402	
403	  template <MatrixUseEnum UseLocal = Use>
404	  typename hlsl::enable_if<Use == MatrixUse::Accumulator && UseLocal == Use,
405	                           void>::type
406	  InterlockedAccumulate(RWByteAddressBuffer Res, uint StartOffset, uint Stride,
407	                        MatrixLayoutEnum Layout,
408	                        uint Align = sizeof(ElementType)) {
409	    __builtin_LinAlg_MatrixAccumulateToDescriptor(__handle, Res, StartOffset,
410	                                                  Stride, Layout, Align);
411	  }
412	};
