418	template <ComponentEnum OutTy, ComponentEnum ATy, ComponentEnum BTy,
419	          SIZE_TYPE M, SIZE_TYPE N, SIZE_TYPE K>
420	Matrix<OutTy, M, N, MatrixUse::Accumulator, MatrixScope::Wave>
421	Multiply(const Matrix<ATy, M, K, MatrixUse::A, MatrixScope::Wave> MatrixA,
422	         const Matrix<BTy, K, N, MatrixUse::B, MatrixScope::Wave> MatrixB) {
423	  Matrix<OutTy, M, N, MatrixUse::Accumulator, MatrixScope::Wave> Result;
424	  __builtin_LinAlg_MatrixMatrixMultiply(Result.__handle, MatrixA.__handle,
425	                                        MatrixB.__handle);
426	  return Result;
427	}
