461	// Cooperative Vector Replacement API
462	// Cooperative Vector operates on per-thread vectors multiplying against B
463	// matrices with thread scope.
464	
465	template <typename OutputElTy, typename InputElTy, SIZE_TYPE M, SIZE_TYPE K,
466	          ComponentEnum MatrixDT>
467	// clang-format off
468	typename hlsl::enable_if<hlsl::is_arithmetic<InputElTy>::value, vector<OutputElTy, M> >::type
469	// clang-format on
470	Multiply(Matrix<MatrixDT, M, K, MatrixUse::A, MatrixScope::Thread> MatrixA,
471	         vector<InputElTy, K> Vec) {
472	  vector<OutputElTy, M> Result;
473	  __builtin_LinAlg_MatrixVectorMultiply(Result, MatrixA.__handle,
474	                                        hlsl::is_signed<OutputElTy>::value, Vec,
475	                                        MatrixDT);
476	  return Result;
477	}
478	
479	template <typename OutputElTy, typename InputElTy, typename BiasElTy,
480	          SIZE_TYPE M, SIZE_TYPE K, ComponentEnum MatrixDT>
481	// clang-format off
482	typename hlsl::enable_if<hlsl::is_arithmetic<InputElTy>::value, vector<OutputElTy, M> >::type
483	// clang-format on
484	MultiplyAdd(Matrix<MatrixDT, M, K, MatrixUse::A, MatrixScope::Thread> MatrixA,
485	            vector<InputElTy, K> Vec, vector<BiasElTy, M> Bias) {
486	  vector<OutputElTy, M> Result;
487	  __builtin_LinAlg_MatrixVectorMultiplyAdd(Result, MatrixA.__handle,
488	                                           hlsl::is_signed<OutputElTy>::value,
489	                                           Vec, MatrixDT, Bias, MatrixDT);
490	  return Result;
491	}
492	
493	template <typename OutputElTy, typename InputElTy, ComponentEnum InputInterp,
494	          typename BiasElTy, SIZE_TYPE M, SIZE_TYPE VecK, SIZE_TYPE K,
495	          ComponentEnum MatrixDT>
496	// clang-format off
497	typename hlsl::enable_if<
498	    InterpretedVector<InputElTy, VecK, InputInterp>::Size == K,
499	    vector<OutputElTy, M> >::type
500	// clang-format on
501	MultiplyAdd(Matrix<MatrixDT, M, K, MatrixUse::A, MatrixScope::Thread> MatrixA,
502	            InterpretedVector<InputElTy, VecK, InputInterp> InterpVec,
503	            vector<BiasElTy, M> Bias) {
504	  vector<OutputElTy, M> Result;
505	  __builtin_LinAlg_MatrixVectorMultiplyAdd(
506	      Result, MatrixA.__handle, hlsl::is_signed<OutputElTy>::value,
507	      InterpVec.Data, InterpVec.Interpretation, Bias, MatrixDT);
508	  return Result;
509	}
510	
511	template <typename OutputElTy, typename InputElTy, ComponentEnum BiasElTy,
512	          SIZE_TYPE M, SIZE_TYPE K, ComponentEnum MatrixDT>
513	// clang-format off
514	typename hlsl::enable_if<hlsl::is_arithmetic<InputElTy>::value,
515	                         vector<OutputElTy, M> >::type
516	// clang-format on
517	MultiplyAdd(Matrix<MatrixDT, M, K, MatrixUse::A, MatrixScope::Thread> MatrixA,
518	            vector<InputElTy, K> Vec, VectorRef<BiasElTy, M> BiasRef) {
519	  using BiasVecTy =
520	      vector<typename __detail::ComponentTypeTraits<BiasElTy>::Type, M>;
521	  BiasVecTy BiasVec = BiasRef.Buf.template Load<BiasVecTy>(BiasRef.Offset);
522	  vector<OutputElTy, M> Result;
523	  __builtin_LinAlg_MatrixVectorMultiplyAdd(Result, MatrixA.__handle,
524	                                           hlsl::is_signed<OutputElTy>::value,
525	                                           Vec, MatrixDT, BiasVec, BiasElTy);
526	  return Result;
527	}
528	
529	template <typename OutputElTy, typename InputElTy, ComponentEnum InputInterp,
530	          ComponentEnum BiasElTy, SIZE_TYPE M, SIZE_TYPE VecK, SIZE_TYPE K,
531	          ComponentEnum MatrixDT>
532	// clang-format off
533	typename hlsl::enable_if<
534	    InterpretedVector<InputElTy, VecK, InputInterp>::Size == K,
535	    vector<OutputElTy, M> >::type
536	// clang-format on
537	MultiplyAdd(Matrix<MatrixDT, M, K, MatrixUse::A, MatrixScope::Thread> MatrixA,
538	            InterpretedVector<InputElTy, VecK, InputInterp> InterpVec,
539	            VectorRef<BiasElTy, M> BiasRef) {
540	  using BiasVecTy =
541	      vector<typename __detail::ComponentTypeTraits<BiasElTy>::Type, M>;
542	  BiasVecTy BiasVec = BiasRef.Buf.template Load<BiasVecTy>(BiasRef.Offset);
543	  vector<OutputElTy, M> Result;
544	  __builtin_LinAlg_MatrixVectorMultiplyAdd(
545	      Result, MatrixA.__handle, hlsl::is_signed<OutputElTy>::value,
546	      InterpVec.Data, InterpVec.Interpretation, BiasVec, BiasElTy);
547	  return Result;
548	}
