550	// Outer product functions
551	template <ComponentEnum OutTy, typename InputElTy, SIZE_TYPE M, SIZE_TYPE N>
552	Matrix<OutTy, M, N, MatrixUse::Accumulator, MatrixScope::Thread>
553	OuterProduct(vector<InputElTy, M> VecA, vector<InputElTy, N> VecB) {
554	  Matrix<OutTy, M, N, MatrixUse::Accumulator, MatrixScope::Thread> Result;
555	  __builtin_LinAlg_MatrixOuterProduct(Result.__handle, VecA, VecB);
556	  return Result;
557	}
